export function searchEmoji(query: string): EmojiEntry[] {
  if (!query.trim()) return [];
  const q = query.toLowerCase().trim();
  return EMOJI_INDEX.filter(
    (e) =>
      e.name.toLowerCase().includes(q) ||
      e.keywords.some((k) => k.toLowerCase().includes(q))
  );
}